package com.agrios.platform.inventory.domain;
import jakarta.persistence.*; import java.math.BigDecimal; import java.time.*; import java.util.UUID;
@Entity @Table(name="stock_movement",schema="inventory")
public class StockMovementEntity { @Id private UUID id; @Column(nullable=false)private UUID tenantId; @Column(nullable=false)private UUID inventoryItemId; private UUID inventoryLotId; @Column(nullable=false)private String movementType; @Column(nullable=false)private BigDecimal quantity; @Column(nullable=false)private String unitCode; @Column(nullable=false)private LocalDate movementDate; @Column(nullable=false)private String sourceModule; @Column(nullable=false)private String sourceReferenceType; private UUID sourceReferenceId; @Column(nullable=false)private String idempotencyKey; @Column(columnDefinition="text")private String notes; @Column(nullable=false)private Instant createdAt; private UUID createdBy; protected StockMovementEntity(){}
 public static StockMovementEntity create(UUID t,UUID item,UUID lot,String type,BigDecimal q,String unit,LocalDate date,String module,String refType,UUID refId,String key,String notes,UUID actor){var v=new StockMovementEntity();v.id=UUID.randomUUID();v.tenantId=t;v.inventoryItemId=item;v.inventoryLotId=lot;v.movementType=type;v.quantity=q;v.unitCode=unit;v.movementDate=date;v.sourceModule=module;v.sourceReferenceType=refType;v.sourceReferenceId=refId;v.idempotencyKey=key;v.notes=notes;v.createdAt=Instant.now();v.createdBy=actor;return v;} public UUID id(){return id;}
}
